parameters.jsCode:
// Prepare URLs for background crawling
const config = $input.first().json;
const seedUrls = config.seedUrls.split(',').map(url => url.trim());

// Process up to 2 URLs for testing
const urlsToProcess = seedUrls.slice(0, 2);

return urlsToProcess.map(url => ({
  json: {
    url: url,
    type: 'seed',
    startTime: new Date().toISOString()
  }
}));

// Process the fetched content
const item = $input.first().json;
const htmlContent = item.data || '';

// Extract title and basic content
const titleMatch = htmlContent.match(/<title[^>]*>([^<]+)</i);
const title = titleMatch ? titleMatch[1].trim() : 'No title';

const textContent = htmlContent
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const wordCount = textContent.split(' ').length;
const contentPreview = textContent.substring(0, 500);

// Extract key policy information
const year = item.url.match(/20\d{2}/) ? item.url.match(/20\d{2}/)[0] : 'unknown';
const policyKeywords = [];
if (contentPreview.toLowerCase().includes('housing')) policyKeywords.push('housing');
if (contentPreview.toLowerCase().includes('economy')) policyKeywords.push('economy');
if (contentPreview.toLowerCase().includes('education')) policyKeywords.push('education');
if (contentPreview.toLowerCase().includes('health')) policyKeywords.push('healthcare');

// Save comprehensive result
return [{
  json: {
    url: item.url,
    title: title,
    year: year,
    wordCount: wordCount,
    contentPreview: contentPreview,
    policyKeywords: policyKeywords,
    processedAt: new Date().toISOString(),
    success: true,
    metadata: {
      contentLength: htmlContent.length,
      hasContent: wordCount > 50
    }
  }
}];
